#include <stdio.h>

// Function to update value at a memory address
void updateValue(int *p) {
    *p = *p * 2;
}

int main() {
    int num = 100;
    int *ptr = &num;

    printf("Original num: %d\n", num);
    printf("Address of num: %p\n", ptr);

    // Accessing via pointer
    printf("Value via pointer (*ptr): %d\n", *ptr);

    // Changing value via pointer
    *ptr = 200;
    printf("New num (changed via ptr): %d\n", num);

    // Pointer Arithmetic with Array
    printf("\n--- Array Traversal ---\n");
    int arr[] = {10, 20, 30};
    int *pArray = arr;

    for(int i=0; i<3; i++) {
        printf("Element %d: %d (Address: %p)\n", i, *(pArray + i), (pArray + i));
    }

    // Call by reference
    printf("\n--- Call by Reference ---\n");
    printf("Before update: %d\n", num);
    updateValue(&num);
    printf("After update: %d\n", num);

    return 0;
}
